14	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders;
15	
16	internal static class SourceValueBuilder
17	{
18	    /// <summary>
19	    /// Tries to build an <see cref="ISourceValue"/> instance which serializes as an expression,
20	    /// with a value that is assignable to the target member requested in the <paramref name="memberMappingInfo"/>.
21	    /// </summary>
22	    public static bool TryBuildMappedSourceValue(
23	        IMembersBuilderContext<IMapping> ctx,
24	        MemberMappingInfo memberMappingInfo,
25	        [NotNullWhen(true)] out ISourceValue? sourceValue
26	    ) => TryBuildMappedSourceValue(ctx, memberMappingInfo, MemberMappingBuilder.CodeStyle.Expression, out sourceValue);
27	
28	    /// <summary>
29	    /// Tries to build an <see cref="ISourceValue"/> instance,
30	    /// with a value that is assignable to the target member requested in the <paramref name="memberMappingInfo"/>.
31	    /// </summary>
32	    public static bool TryBuildMappedSourceValue(
33	        IMembersBuilderContext<IMapping> ctx,
34	        MemberMappingInfo memberMappingInfo,
35	        MemberMappingBuilder.CodeStyle codeStyle,
36	        [NotNullWhen(true)] out ISourceValue? sourceValue
37	    )
38	    {
39	        if (memberMappingInfo.ValueConfiguration != null)
40	            return TryBuildValue(ctx, memberMappingInfo, out sourceValue);
41	
42	        if (memberMappingInfo.SourceMember != null)
43	            return MemberMappingBuilder.TryBuild(ctx, memberMappingInfo, codeStyle, out sourceValue);
44	
45	        sourceValue = null;
46	        return false;
47	    }
48	
49	    private static bool TryBuildValue(
50	        IMembersBuilderContext<IMapping> ctx,
51	        MemberMappingInfo memberMappingInfo,
52	        [NotNullWhen(true)] out ISourceValue? sourceValue
53	    )
54	    {
55	        // always set the member mapped,
56	        // as other diagnostics are reported if the mapping fails to be built
57	        ctx.SetMembersMapped(memberMappingInfo);
58	
59	        if (memberMappingInfo.ValueConfiguration!.Value != null)
60	            return TryBuildConstantSourceValue(ctx, memberMappingInfo, out sourceValue);
61	
62	        if (memberMappingInfo.ValueConfiguration!.Use != null)
63	            return TryBuildMethodProvidedSourceValue(ctx, memberMappingInfo, out sourceValue);
64	
65	        throw new InvalidOperationException($"Illegal {nameof(MemberValueMappingConfiguration)}");
66	    }
67	
68	    private static bool TryBuildConstantSourceValue(
69	        IMembersBuilderContext<IMapping> ctx,
70	        MemberMappingInfo memberMappingInfo,
71	        [NotNullWhen(true)] out ISourceValue? sourceValue
72	    )
73	    {
74	        var value = memberMappingInfo.ValueConfiguration!.Value!.Value;
75	
76	        // the target is a non-nullable reference type,
77	        // but the provided value is null or default (for default IsNullable is also true)
78	        if (
79	            value.ConstantValue.IsNull
80	            && memberMappingInfo.TargetMember.MemberType.IsReferenceType
81	            && !memberMappingInfo.TargetMember.Member.IsNullable
82	        )
83	        {
84	            ctx.BuilderContext.ReportDiagnostic(
85	                DiagnosticDescriptors.CannotMapValueNullToNonNullable,
86	                memberMappingInfo.TargetMember.ToDisplayString()
87	            );
88	            sourceValue = new ConstantSourceValue(SuppressNullableWarning(value.Expression));
89	            return true;
90	        }
91	
92	        // target is value type but value is null
93	        if (
94	            value.ConstantValue.IsNull
95	            && memberMappingInfo.TargetMember.MemberType.IsValueType
96	            && !memberMappingInfo.TargetMember.MemberType.IsNullableValueType()
97	            && value.Expression.IsKind(SyntaxKind.NullLiteralExpression)
98	        )
99	        {
100	            ctx.BuilderContext.ReportDiagnostic(
101	                DiagnosticDescriptors.CannotMapValueNullToNonNullable,
102	                memberMappingInfo.TargetMember.ToDisplayString()
103	            );
104	            sourceValue = new ConstantSourceValue(DefaultLiteral());
105	            return true;
106	        }
107	
108	        // the target accepts null and the value is null or default
109	        // use the expression instant of a constant null literal
110	        // to use "default" or "null" depending on what the user specified in the attribute
111	        if (value.ConstantValue.IsNull)
112	        {
113	            sourceValue = new ConstantSourceValue(value.Expression);
114	            return true;
115	        }
116	
117	        // use non-nullable target type to allow non-null value type assignments
118	        // to nullable value types
119	        if (!SymbolEqualityComparer.Default.Equals(value.ConstantValue.Type, memberMappingInfo.TargetMember.MemberType.NonNullable()))
120	        {
121	            ctx.BuilderContext.ReportDiagnostic(
122	                DiagnosticDescriptors.MapValueTypeMismatch,
123	                value.Expression.ToFullString(),
124	                value.ConstantValue.Type?.ToDisplayString() ?? "unknown",
125	                memberMappingInfo.TargetMember.ToDisplayString()
126	            );
127	            sourceValue = null;
128	            return false;
129	        }
130	
131	        switch (value.ConstantValue.Kind)
132	        {
133	            case TypedConstantKind.Primitive:
134	                sourceValue = new ConstantSourceValue(value.Expression);
135	                return true;
136	            case TypedConstantKind.Enum:
137	                // expand enum member access to fully qualified identifier
138	                // use simple member name approach instead of slower visitor pattern on the expression
139	                var enumMemberName = ((MemberAccessExpressionSyntax)value.Expression).Name.Identifier.Text;
140	                var enumTypeFullName = FullyQualifiedIdentifier(memberMappingInfo.TargetMember.MemberType.NonNullable());
141	                sourceValue = new ConstantSourceValue(MemberAccess(enumTypeFullName, enumMemberName));
142	                return true;
143	            case TypedConstantKind.Type:
144	            case TypedConstantKind.Array:
145	                ctx.BuilderContext.ReportDiagnostic(DiagnosticDescriptors.MapValueUnsupportedType, value.ConstantValue.Kind.ToString());
146	                break;
147	        }
148	
149	        sourceValue = null;
150	        return false;
151	    }
152	
153	    private static bool TryBuildMethodProvidedSourceValue(
154	        IMembersBuilderContext<IMapping> ctx,
155	        MemberMappingInfo memberMappingInfo,
156	        [NotNullWhen(true)] out ISourceValue? sourceValue
157	    )
158	    {
159	        var methodReferenceConfiguration = memberMappingInfo.ValueConfiguration!.Use!;
160	        var targetSymbol = methodReferenceConfiguration.GetTargetType(ctx.BuilderContext);
161	        var scope = ctx.BuilderContext.ParameterScope;
162	        var allNamedMethods = targetSymbol is null
163	            ? []
164	            : ctx
165	                .BuilderContext.SymbolAccessor.GetAllDirectlyAccessibleMethods(targetSymbol)
166	                .Where(m =>
167	                    m is { IsAsync: false, ReturnsVoid: false, IsGenericMethod: false }
168	                    && ctx.BuilderContext.AttributeAccessor.IsMappingNameEqualTo(m, methodReferenceConfiguration.Name)
169	                )
170	                .ToList();
171	
172	        var namedMethodCandidates = allNamedMethods.Where(m => scope.CanMatchParameters(m)).ToList();
173	
174	        if (namedMethodCandidates.Count == 0)
175	        {
176	            var descriptor =
177	                allNamedMethods.Count > 0
178	                    ? DiagnosticDescriptors.MapValueMethodParametersUnsatisfied
179	                    : DiagnosticDescriptors.MapValueReferencedMethodNotFound;
180	            ctx.BuilderContext.ReportDiagnostic(descriptor, methodReferenceConfiguration.FullName);
181	            sourceValue = null;
182	            return false;
183	        }
184	
185	        // use non-nullable to allow non-null value type assignments
186	        // to nullable value types
187	        // nullable is checked with nullable annotation
188	        var methodCandidates = namedMethodCandidates.Where(x =>
189	            SymbolEqualityComparer.Default.Equals(x.ReturnType.NonNullable(), memberMappingInfo.TargetMember.MemberType.NonNullable())
190	        );
191	
192	        if (!memberMappingInfo.TargetMember.Member.IsNullable)
193	        {
194	            // Filter out methods that may return null when the target is non-nullable.
195	            methodCandidates = methodCandidates.Where(m => !ctx.BuilderContext.SymbolAccessor.MayReturnNull(m, false));
196	        }
197	
198	        var methodSymbol = methodCandidates.FirstOrDefault();
199	        if (methodSymbol == null)
200	        {
201	            ctx.BuilderContext.ReportDiagnostic(
202	                DiagnosticDescriptors.MapValueMethodTypeMismatch,
203	                methodReferenceConfiguration.Name,
204	                namedMethodCandidates[0].ReturnType.ToDisplayString(),
205	                memberMappingInfo.TargetMember.ToDisplayString()
206	            );
207	            sourceValue = null;
208	            return false;
209	        }
210	
211	        // Collect additional parameter names and mark them as used
212	        var additionalParameterNames = methodSymbol.Parameters.Select(param => param.Name).ToList();
213	        scope.MarkUsed(additionalParameterNames);
214	
215	        sourceValue = new MethodProvidedSourceValue(
216	            methodSymbol.Name,
217	            methodReferenceConfiguration.GetTargetName(ctx.BuilderContext),
218	            additionalParameterNames
219	        );
220	        return true;
221	    }
222	}
