1	using System.Diagnostics.CodeAnalysis;
2	using Riok.Mapperly.Configuration;
3	using Riok.Mapperly.Configuration.PropertyReferences;
4	using Riok.Mapperly.Descriptors.Mappings.MemberMappings;
5	using Riok.Mapperly.Helpers;
6	using Riok.Mapperly.Symbols;
7	using Riok.Mapperly.Symbols.Members;
8	
9	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders.BuilderContext;
10	
11	/// <summary>
12	/// The state of an ongoing member mapping matching process.
13	/// Contains discovered but unmapped members, ignored members, etc.
14	/// </summary>
15	/// <param name="unmappedSourceMemberNames">Source member names which are not used in a member mapping yet.</param>
16	/// <param name="unmappedTargetMemberNames">Target member names which are not used in a member mapping yet.</param>
17	/// <param name="targetMemberCaseMapping">A dictionary with all members of the target with a case-insensitive key comparer.</param>
18	/// <param name="targetMembers">All known target members.</param>
19	/// <param name="memberValueConfigsByRootTargetName">All value configurations by root target member names, which are not yet consumed.</param>
20	/// <param name="memberConfigsByRootTargetName">All configurations by root target member names, which are not yet consumed.</param>
21	/// <param name="ignoredSourceMemberNames">All ignored source members names.</param>
22	internal class MembersMappingState(
23	    HashSet<string> unmappedSourceMemberNames,
24	    HashSet<string> unmappedTargetMemberNames,
25	    IReadOnlyDictionary<string, string> targetMemberCaseMapping,
26	    Dictionary<string, IMappableMember> targetMembers,
27	    Dictionary<string, List<MemberValueMappingConfiguration>> memberValueConfigsByRootTargetName,
28	    Dictionary<string, List<MemberMappingConfiguration>> memberConfigsByRootTargetName,
29	    Dictionary<string, List<IMemberPathConfiguration>> configuredTargetMembersByRootName,
30	    HashSet<string> ignoredSourceMemberNames,
31	    ParameterScope parameterScope
32	)
33	{
34	    private readonly Dictionary<string, IMappableMember> _aliasedSourceMembers = new(StringComparer.OrdinalIgnoreCase);
35	
36	    /// <summary>
37	    /// All source member names that are not used in a member mapping (yet).
38	    /// </summary>
39	    private readonly HashSet<string> _unmappedSourceMemberNames = unmappedSourceMemberNames;
40	
41	    /// <summary>
42	    /// All target member names that are not used in a member mapping (yet).
43	    /// </summary>
44	    private readonly HashSet<string> _unmappedTargetMemberNames = unmappedTargetMemberNames;
45	
46	    public ParameterScope ParameterScope => parameterScope;
47	
48	    public IReadOnlyCollection<string> IgnoredSourceMemberNames => ignoredSourceMemberNames;
49	
50	    /// <summary>
51	    /// Whether any member mapping has been added.
52	    /// </summary>
53	    public bool HasMemberMapping { get; private set; }
54	
55	    /// <inheritdoc cref="_unmappedSourceMemberNames"/>
56	    public IEnumerable<string> UnmappedSourceMemberNames => _unmappedSourceMemberNames;
57	
58	    public IReadOnlyDictionary<string, IMappableMember> AdditionalSourceMembers =>
59	        field ??= parameterScope.Parameters.Values.ToDictionary<MethodParameter, string, IMappableMember>(
60	            x => x.NormalizedName,
61	            x => new ParameterSourceMember(x),
62	            StringComparer.OrdinalIgnoreCase
63	        );
64	
65	    public IReadOnlyDictionary<string, IMappableMember> AliasedSourceMembers => _aliasedSourceMembers;
66	
67	    public IEnumerable<MemberMappingConfiguration> UnusedMemberConfigs => memberConfigsByRootTargetName.Values.SelectMany(x => x);
68	
69	    public IEnumerable<IMappableMember> EnumerateUnmappedTargetMembers() => _unmappedTargetMemberNames.Select(x => targetMembers[x]);
70	
71	    public IEnumerable<IMappableMember> EnumerateUnmappedOrConfiguredTargetMembers()
72	    {
73	        return _unmappedTargetMemberNames
74	            .Concat(memberValueConfigsByRootTargetName.Keys)
75	            .Concat(memberConfigsByRootTargetName.Keys)
76	            .Distinct()
77	            .Select(targetMembers.GetValueOrDefault)
78	            .WhereNotNull()
79	            // Collect the enumeration since the source may be modified.
80	            // For more context see https://github.com/riok/mapperly/issues/1403#issuecomment-2267571805.
81	            .ToList();
82	    }
83	
84	    public void TryAddSourceMemberAlias(string alias, IMappableMember member) => _aliasedSourceMembers.TryAdd(alias, member);
85	
86	    public void MappingAdded() => HasMemberMapping = true;
87	
88	    public void MappingAdded(MemberMappingInfo info, bool ignoreTargetCasing)
89	    {
90	        MappingAdded();
91	        SetMembersMapped(info, ignoreTargetCasing);
92	    }
93	
94	    public void IgnoreMembers(IMappableMember member) => IgnoreMembers(member.Name);
95	
96	    public void IgnoreMembers(string name)
97	    {
98	        _unmappedSourceMemberNames.Remove(name);
99	        _unmappedTargetMemberNames.Remove(name);
100	        ignoredSourceMemberNames.Add(name);
101	
102	        if (!HasMemberConfig(name))
103	        {
104	            targetMembers.Remove(name);
105	        }
106	    }
107	
108	    public bool HasDuplicatedMemberConfig(NonEmptyMemberPath targetMemberPath)
109	    {
110	        if (!configuredTargetMembersByRootName.TryGetValue(targetMemberPath.RootName, out var configs))
111	            return false;
112	
113	        return configs.Where(targetMemberPath.Equals).Skip(1).Any();
114	    }
115	
116	    public void SetTargetMemberMapped(IMappableMember targetMember) => SetTargetMemberMapped(targetMember.Name);
117	
118	    public void SetTargetMemberMapped(string targetName, bool ignoreCase = false)
119	    {
120	        _unmappedTargetMemberNames.Remove(targetName);
121	
122	        if (ignoreCase && targetMemberCaseMapping.TryGetValue(targetName, out targetName))
123	        {
124	            _unmappedTargetMemberNames.Remove(targetName);
125	        }
126	    }
127	
128	    public void SetMembersMapped(MemberMappingInfo info, bool ignoreTargetCasing)
129	    {
130	        SetTargetMemberMapped(info.TargetMember.Path[0].Name, ignoreTargetCasing);
131	
132	        if (info.SourceMember != null)
133	        {
134	            SetSourceMemberMapped(info.SourceMember);
135	        }
136	
137	        if (info.Configuration != null)
138	        {
139	            ConsumeMemberConfig(info.Configuration);
140	        }
141	
142	        if (info.ValueConfiguration != null)
143	        {
144	            ConsumeMemberConfig(info.ValueConfiguration);
145	        }
146	    }
147	
148	    public void ConsumeMemberConfig(MemberValueMappingConfiguration config) =>
149	        ConsumeMemberConfig(config, config.Target, memberValueConfigsByRootTargetName);
150	
151	    public void ConsumeMemberConfig(MemberMappingConfiguration config) =>
152	        ConsumeMemberConfig(config, config.Target, memberConfigsByRootTargetName);
153	
154	    public bool TryGetMemberConfigs(
155	        string targetMemberName,
156	        bool ignoreCase,
157	        [NotNullWhen(true)] out IReadOnlyList<MemberMappingConfiguration>? memberConfigs
158	    )
159	    {
160	        if (ignoreCase)
161	        {
162	            targetMemberName = targetMemberCaseMapping.GetValueOrDefault(targetMemberName, targetMemberName);
163	        }
164	
165	        if (memberConfigsByRootTargetName.TryGetValue(targetMemberName, out var configs))
166	        {
167	            memberConfigs = configs;
168	            return true;
169	        }
170	
171	        memberConfigs = null;
172	        return false;
173	    }
174	
175	    public bool TryGetMemberValueConfigs(
176	        string targetMemberName,
177	        bool ignoreCase,
178	        [NotNullWhen(true)] out IReadOnlyList<MemberValueMappingConfiguration>? memberConfigs
179	    )
180	    {
181	        if (ignoreCase)
182	        {
183	            targetMemberName = targetMemberCaseMapping.GetValueOrDefault(targetMemberName, targetMemberName);
184	        }
185	
186	        if (memberValueConfigsByRootTargetName.TryGetValue(targetMemberName, out var configs))
187	        {
188	            memberConfigs = configs;
189	            return true;
190	        }
191	
192	        memberConfigs = null;
193	        return false;
194	    }
195	
196	    private void SetSourceMemberMapped(SourceMemberPath sourcePath)
197	    {
198	        if (sourcePath.MemberPath.Path.FirstOrDefault() is not { } sourceMember)
199	        {
200	            // Assume all source members are used when the source object is used itself.
201	            _unmappedSourceMemberNames.Clear();
202	            return;
203	        }
204	
205	        switch (sourcePath.Type)
206	        {
