1	using System.Diagnostics.CodeAnalysis;
2	using Riok.Mapperly.Abstractions;
3	using Riok.Mapperly.Configuration;
4	using Riok.Mapperly.Configuration.PropertyReferences;
5	using Riok.Mapperly.Descriptors.Mappings;
6	using Riok.Mapperly.Descriptors.Mappings.MemberMappings;
7	using Riok.Mapperly.Diagnostics;
8	using Riok.Mapperly.Helpers;
9	using Riok.Mapperly.Symbols.Members;
10	
11	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders.BuilderContext;
12	
13	/// <summary>
14	/// An abstract base implementation of <see cref="IMembersBuilderContext{T}"/>.
15	/// </summary>
16	/// <typeparam name="T">The type of the mapping.</typeparam>
17	public abstract class MembersMappingBuilderContext<T>(MappingBuilderContext builderContext, T mapping) : IMembersBuilderContext<T>
18	    where T : IMapping
19	{
20	    private readonly MembersMappingState _state = MembersMappingStateBuilder.Build(builderContext, mapping);
21	
22	    private readonly NestedMappingsContext _nestedMappingsContext = NestedMappingsContext.Create(builderContext);
23	
24	    public MappingBuilderContext BuilderContext { get; } = builderContext;
25	
26	    public T Mapping { get; } = mapping;
27	
28	    public void AddDiagnostics(bool requiredMembersNeedToBeMapped)
29	    {
30	        MemberMappingDiagnosticReporter.ReportDiagnostics(BuilderContext, _state, requiredMembersNeedToBeMapped);
31	        _nestedMappingsContext.ReportDiagnostics();
32	    }
33	
34	    public IEnumerable<IMappableMember> EnumerateUnmappedTargetMembers() => _state.EnumerateUnmappedTargetMembers();
35	
36	    public IEnumerable<IMappableMember> EnumerateUnmappedOrConfiguredTargetMembers() => _state.EnumerateUnmappedOrConfiguredTargetMembers();
37	
38	    public void TryAddSourceMemberAlias(string alias, IMappableMember member) => _state.TryAddSourceMemberAlias(alias, member);
39	
40	    public void SetTargetMemberMapped(IMappableMember targetMember) => _state.SetTargetMemberMapped(targetMember);
41	
42	    protected void SetTargetMemberMapped(string targetMemberName, bool ignoreCase = false) =>
43	        _state.SetTargetMemberMapped(targetMemberName, ignoreCase);
44	
45	    public void SetMembersMapped(MemberMappingInfo members) => _state.SetMembersMapped(members, false);
46	
47	    public void IgnoreMembers(IMappableMember member) => _state.IgnoreMembers(member);
48	
49	    public void IgnoreMembers(string memberName) => _state.IgnoreMembers(memberName);
50	
51	    public void ConsumeMemberConfigs(MemberMappingInfo members)
52	    {
53	        if (members.Configuration != null)
54	        {
55	            ConsumeMemberConfig(members.Configuration);
56	        }
57	
58	        if (members.ValueConfiguration != null)
59	        {
60	            ConsumeMemberConfig(members.ValueConfiguration);
61	        }
62	    }
63	
64	    public bool HasDuplicatedMemberConfig(NonEmptyMemberPath targetMemberPath) => _state.HasDuplicatedMemberConfig(targetMemberPath);
65	
66	    public void MappingAdded() => _state.MappingAdded();
67	
68	    protected void MappingAdded(MemberMappingInfo info, bool ignoreTargetCasing = false) => _state.MappingAdded(info, ignoreTargetCasing);
69	
70	    protected void ConsumeMemberConfig(MemberMappingConfiguration config) => _state.ConsumeMemberConfig(config);
71	
72	    protected void ConsumeMemberConfig(MemberValueMappingConfiguration config) => _state.ConsumeMemberConfig(config);
73	
74	    public IEnumerable<MemberMappingInfo> MatchMembers(IMappableMember targetMember)
75	    {
76	        var matchedMemberMappingInfos = new List<MemberMappingInfo>();
77	        if (TryGetMemberValueConfigs(targetMember.Name, false, out var memberValueConfigs))
78	        {
79	            matchedMemberMappingInfos.AddRange(ResolveMemberMappingInfo(memberValueConfigs.ToList()));
80	        }
81	
82	        if (TryGetMemberConfigs(targetMember.Name, false, out var memberConfigs))
83	        {
84	            matchedMemberMappingInfos.AddRange(ResolveMemberMappingInfo(memberConfigs.ToList()));
85	        }
86	
87	        if (matchedMemberMappingInfos.Count > 0)
88	        {
89	            // return configs with shorter target member paths first
90	            // to prevent NRE's in the generated code
91	            return matchedMemberMappingInfos.OrderBy(x => x.TargetMember.Path.Count);
92	        }
93	
94	        // match directly
95	        if (TryFindSourcePath(targetMember.Name, out var sourceMemberPath))
96	        {
97	            return [new MemberMappingInfo(sourceMemberPath, new NonEmptyMemberPath(Mapping.TargetType, [targetMember]))];
98	        }
99	
100	        return [];
101	    }
102	
103	    protected bool TryMatchMember(IMappableMember targetMember, [NotNullWhen(true)] out MemberMappingInfo? memberInfo) =>
104	        TryMatchMember(targetMember, null, out memberInfo);
105	
106	    protected bool TryMatchMember(IMappableMember targetMember, bool? ignoreCase, [NotNullWhen(true)] out MemberMappingInfo? memberInfo)
107	    {
108	        if (TryGetConfiguredMemberMappingInfo(targetMember, ignoreCase == true, out memberInfo))
109	            return true;
110	
111	        // if no config was found, match the source path
112	        if (TryFindSourcePath(targetMember.Name, out var sourceMemberPath, ignoreCase))
113	        {
114	            memberInfo = new MemberMappingInfo(sourceMemberPath, new NonEmptyMemberPath(BuilderContext.Target, [targetMember]));
115	            return true;
116	        }
117	
118	        memberInfo = null;
119	        return false;
120	    }
121	
122	    protected bool TryGetMemberConfigs(
123	        string targetMemberName,
124	        bool ignoreCase,
125	        [NotNullWhen(true)] out IReadOnlyList<MemberMappingConfiguration>? memberConfigs
126	    ) => _state.TryGetMemberConfigs(targetMemberName, ignoreCase, out memberConfigs);
127	
128	    protected bool TryGetMemberValueConfigs(
129	        string targetMemberName,
130	        bool ignoreCase,
131	        [NotNullWhen(true)] out IReadOnlyList<MemberValueMappingConfiguration>? memberConfigs
132	    ) => _state.TryGetMemberValueConfigs(targetMemberName, ignoreCase, out memberConfigs);
133	
134	    protected virtual bool TryFindSourcePath(
135	        IEnumerable<StringMemberPath> pathCandidates,
136	        bool ignoreCase,
137	        [NotNullWhen(true)] out SourceMemberPath? sourcePath
138	    )
139	    {
140	        // try to match in additional source members
141	        if (
142	            BuilderContext.SymbolAccessor.TryFindMemberPath(
143	                _state.AdditionalSourceMembers,
144	                pathCandidates,
145	                ignoreCase,
146	                out var sourceMemberPath
147	            )
148	        )
149	        {
150	            sourcePath = new SourceMemberPath(sourceMemberPath, SourceMemberType.AdditionalMappingMethodParameter);
151	            return true;
152	        }
153	
154	        // try to match in aliased source members
155	        if (BuilderContext.SymbolAccessor.TryFindMemberPath(_state.AliasedSourceMembers, pathCandidates, ignoreCase, out sourceMemberPath))
156	        {
157	            sourcePath = new SourceMemberPath(sourceMemberPath, SourceMemberType.MemberAlias);
158	            return true;
159	        }
160	
161	        // match against source type members
162	        if (
163	            BuilderContext.SymbolAccessor.TryFindMemberPath(
164	                Mapping.SourceType,
165	                pathCandidates,
166	                _state.IgnoredSourceMemberNames,
167	                ignoreCase,
168	                out sourceMemberPath
169	            )
170	        )
171	        {
172	            sourcePath = new SourceMemberPath(sourceMemberPath, SourceMemberType.Member);
